import React, { useEffect, useState } from 'react';
import {
    Box,
    TextField,
    Button,
    Typography,
    MenuItem,
    Alert,
    Card,
    CardContent
} from '@mui/material';
import api from '../../services/api';

const CreateUser = () => {

    const [form, setForm] = useState({
        username: '',
        email: '',
        password: '',
        employee_id: '',
        role: '',
        state: '',
        branch: '',
        area: ''
    });

    const [roles, setRoles] = useState([]);
    const [states, setStates] = useState([]);
    const [branches, setBranches] = useState([]);
    const [areas, setAreas] = useState([]);

    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    // ================= LOAD MASTER DATA =================
    useEffect(() => {
        loadMasters();
    }, []);

    const loadMasters = async () => {
        try {
            const [r, s] = await Promise.all([
                api.getRoles(),
                api.getStates()
            ]);

            setRoles(r.data);
            setStates(s.data);

        } catch (err) {
            console.error(err);
        }
    };

    // ================= HANDLE CHANGE =================
    const handleChange = (e) => {
        setForm({ ...form, [e.target.name]: e.target.value });
    };

    // ================= LOAD BRANCH =================
    const handleStateChange = async (stateId) => {
        setForm({ ...form, state: stateId, branch: '', area: '' });

        const res = await api.getBranches(stateId);
        setBranches(res.data);
    };

    // ================= LOAD AREA =================
    const handleBranchChange = async (branchId) => {
        setForm({ ...form, branch: branchId, area: '' });

        const res = await api.getAreas(branchId);
        setAreas(res.data);
    };

    // ================= SUBMIT =================
    const handleSubmit = async () => {

        setError('');
        setSuccess('');

        try {
            await api.createUser(form);

            setSuccess("User created successfully");

            // reset form
            setForm({
                username: '',
                email: '',
                password: '',
                employee_id: '',
                role: '',
                state: '',
                branch: '',
                area: ''
            });

        } catch (err) {
            setError(
                err.response?.data?.detail ||
                err.response?.data?.role ||
                "Failed to create user"
            );
        }
    };

    return (
        <Box sx={{ p: 3 }}>
            <Card>
                <CardContent>

                    <Typography variant="h5" gutterBottom>
                        Create User
                    </Typography>

                    {error && <Alert severity="error">{error}</Alert>}
                    {success && <Alert severity="success">{success}</Alert>}

                    <TextField
                        fullWidth
                        label="Username"
                        name="username"
                        value={form.username}
                        onChange={handleChange}
                        sx={{ mt: 2 }}
                    />

                    <TextField
                        fullWidth
                        label="Email"
                        name="email"
                        value={form.email}
                        onChange={handleChange}
                        sx={{ mt: 2 }}
                    />

                    <TextField
                        fullWidth
                        label="Password"
                        name="password"
                        type="password"
                        value={form.password}
                        onChange={handleChange}
                        sx={{ mt: 2 }}
                    />

                    <TextField
                        fullWidth
                        label="Employee ID"
                        name="employee_id"
                        value={form.employee_id}
                        onChange={handleChange}
                        sx={{ mt: 2 }}
                    />

                    {/* ROLE */}
                    <TextField
                        select
                        fullWidth
                        label="Role"
                        name="role"
                        value={form.role}
                        onChange={handleChange}
                        sx={{ mt: 2 }}
                    >
                        {roles.map(r => (
                            <MenuItem key={r.id} value={r.id}>
                                {r.name}
                            </MenuItem>
                        ))}
                    </TextField>

                    {/* STATE */}
                    <TextField
                        select
                        fullWidth
                        label="State"
                        value={form.state}
                        onChange={(e) => handleStateChange(e.target.value)}
                        sx={{ mt: 2 }}
                    >
                        {states.map(s => (
                            <MenuItem key={s.id} value={s.id}>
                                {s.name}
                            </MenuItem>
                        ))}
                    </TextField>

                    {/* BRANCH */}
                    <TextField
                        select
                        fullWidth
                        label="Branch"
                        value={form.branch}
                        onChange={(e) => handleBranchChange(e.target.value)}
                        sx={{ mt: 2 }}
                    >
                        {branches.map(b => (
                            <MenuItem key={b.id} value={b.id}>
                                {b.name}
                            </MenuItem>
                        ))}
                    </TextField>

                    {/* AREA */}
                    <TextField
                        select
                        fullWidth
                        label="Area"
                        name="area"
                        value={form.area}
                        onChange={handleChange}
                        sx={{ mt: 2 }}
                    >
                        {areas.map(a => (
                            <MenuItem key={a.id} value={a.id}>
                                {a.name}
                            </MenuItem>
                        ))}
                    </TextField>

                    <Button
                        variant="contained"
                        fullWidth
                        sx={{ mt: 3 }}
                        onClick={handleSubmit}
                    >
                        Create User
                    </Button>

                </CardContent>
            </Card>
        </Box>
    );
};

export default CreateUser;